use crate::kernel::NexKernel;
use std::time::{SystemTime, UNIX_EPOCH};
use std::fs::OpenOptions;
use std::io::Write;

/// Tamper-Evidence Audit Logger.
/// Every log entry is hashed with the previous entry's hash (Blockchain-like).
/// This ensures logs cannot be deleted or modified in the middle without invalidating the chain.

pub struct AuditLogger {
    last_hash: String,
    log_file_path: String,
    kernel: NexKernel,
}

impl AuditLogger {
    pub fn new(path: &str) -> Self {
        Self {
            last_hash: "GENESIS_HASH".to_string(),
            log_file_path: path.to_string(),
            kernel: NexKernel::new(1),
        }
    }
    
    pub fn log(&mut self, event_type: &str, user: &str, details: &str) {
        let timestamp = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
        
        let record = format!("{}|{}|{}|{}|{}", self.last_hash, timestamp, event_type, user, details);
        
        // Compute Hash of this record
        let hash_bytes = self.kernel.hash_bytes(record.as_bytes(), "Audit-Chain");
        // Simple hex encode
        let hash_hex = crate::integrity::merkle::hex_util::encode(&hash_bytes);
        
        let log_entry = format!("SHA:{} >>> {}\n", hash_hex, record);
        
        // Write to file
        if let Ok(mut file) = OpenOptions::new().create(true).append(true).open(&self.log_file_path) {
            let _ = file.write_all(log_entry.as_bytes());
        }
        
        self.last_hash = hash_hex;
    }
}
